    87→    /// <summary>
    88→    /// Coordinates incoming event stream and dispatches to registered KPI strategies.
    89→    /// Takes care of parallelism, back-pressure, exception isolation, and durability (S3 write).
    90→    /// </summary>
    91→    public sealed class KpiTransformationEngine : IAsyncDisposable
    92→    {
    93→        private readonly IReadOnlyList<IKpiCalculationStrategy> _strategies;
    94→        private readonly IS3KpiWriter                           _writer;
    95→        private readonly ILogger<KpiTransformationEngine>       _logger;
    96→        private readonly SemaphoreSlim                          _parallelism;
    97→
    98→        public KpiTransformationEngine(
    99→            IEnumerable<IKpiCalculationStrategy> strategies,
   100→            IS3KpiWriter                           writer,
   101→            ILogger<KpiTransformationEngine>       logger,
   102→            int                                    maxDegreeOfParallelism = 8)
   103→        {
   104→            _strategies   = strategies?.ToList() ?? throw new ArgumentNullException(nameof(strategies));
   105→            _writer       = writer     ?? throw new ArgumentNullException(nameof(writer));
   106→            _logger       = logger     ?? throw new ArgumentNullException(nameof(logger));
   107→            if (!_strategies.Any())
   108→                throw new ArgumentException("At least one KPI strategy must be provided.", nameof(strategies));
   109→
   110→            _parallelism  = new SemaphoreSlim(maxDegreeOfParallelism, maxDegreeOfParallelism);
   111→        }
   112→
   113→        /// <summary>
   114→        /// Orchestrates transformation for a batch of events.
   115→        /// </summary>
   116→        public async ValueTask ExecuteAsync(
   117→            IEnumerable<EventEnvelope> events,
   118→            CancellationToken         ct = default)
   119→        {
   120→            ArgumentNullException.ThrowIfNull(events);
   121→
   122→            var tasks = new List<Task>();
   123→
   124→            foreach (var envelope in events)
   125→            {
   126→                await _parallelism.WaitAsync(ct).ConfigureAwait(false);
   127→
   128→                // Fire-and-forget – safe because we await all tasks in the list below
   129→                tasks.Add(Task.Run(async () =>
   130→                {
   131→                    try
   132→                    {
   133→                        await DispatchToStrategiesAsync(envelope, ct).ConfigureAwait(false);
   134→                    }
   135→                    catch (Exception ex)
   136→                    {
   137→                        _logger.LogError(ex,
   138→                            "Uncaught exception while processing event {EventId}. " +
   139→                            "The event will be re-queued to the DLQ by the Lambda runtime.",
   140→                            envelope.EventId);
   141→                        // Bubble up to trigger Lambda DLQ – do NOT swallow
   142→                        throw;
   143→                    }
   144→                    finally
   145→                    {
   146→                        _parallelism.Release();
   147→                    }
   148→                }, ct));
   149→            }
   150→
   151→            await Task.WhenAll(tasks).ConfigureAwait(false);
   152→        }
   153→
   154→        private async Task DispatchToStrategiesAsync(EventEnvelope envelope, CancellationToken ct)
   155→        {
   156→            var sw = Stopwatch.StartNew();
   157→
   158→            var interestedStrategies = _strategies.Where(s => s.CanHandle(envelope)).ToArray();
   159→            if (interestedStrategies.Length == 0)
   160→            {
   161→                _logger.LogDebug("No KPI strategy registered for event {EventType}.", envelope.EventType);
   162→                return;
   163→            }
   164→
   165→            var kpiRows = new ConcurrentBag<KpiCalculationResult>();
   166→
   167→            // Parallel but limited to #strategies so trivial overhead
   168→            var strategyTasks = interestedStrategies.Select(async strategy =>
   169→            {
   170→                try
   171→                {
   172→                    var rows = await strategy.ProcessAsync(envelope, ct).ConfigureAwait(false);
   173→                    foreach (var row in rows) kpiRows.Add(row);
   174→                }
   175→                catch (Exception ex)
   176→                {
   177→                    _logger.LogWarning(ex,
   178→                        "Strategy {KpiStrategy} failed while processing EventId={EventId}. Skipping strategy.",
   179→                        strategy.KpiName, envelope.EventId);
   180→                }
   181→            });
   182→
   183→            await Task.WhenAll(strategyTasks).ConfigureAwait(false);
   184→
   185→            // Commit results to the Data Lake (S3, parquet files partitioned by YYYY/MM/DD)
   186→            if (kpiRows.Count > 0)
   187→            {
   188→                await _writer.WriteAsync(kpiRows, ct).ConfigureAwait(false);
   189→            }
   190→
   191→            _logger.LogInformation(
   192→                "Processed EventId={EventId} in {ElapsedMs:n0} ms with {RowCount} KPI rows.",
   193→                envelope.EventId, sw.ElapsedMilliseconds, kpiRows.Count);
   194→        }
