   282→    /// <summary>
   283→    /// Computes deployment lead-time (commit → production) on a per-repo basis.
   284→    /// Maintains a small in-memory buffer which is flushed every <see cref="FlushInterval"/>.
   285→    /// </summary>
   286→    internal sealed class DeploymentLeadTimeStrategy : IKpiCalculationStrategy, IDisposable
   287→    {
   288→        private const string CommitEventType     = "CodeCommitPushed";
   289→        private const string ProdDeployEventType = "CdPipelineDeployed";
   290→
   291→        private readonly TimeSpan                               FlushInterval     = TimeSpan.FromMinutes(5);
   292→        private readonly ConcurrentDictionary<string, DateTime> _commitTimestamps = new(StringComparer.Ordinal);
   293→        private readonly Timer                                  _flushTimer;
   294→        private readonly ILogger                                _logger;
   295→
   296→        public string KpiName => "deployment_lead_time";
   297→
   298→        public DeploymentLeadTimeStrategy(ILogger<DeploymentLeadTimeStrategy> logger)
   299→        {
   300→            _logger      = logger;
   301→            _flushTimer  = new Timer(_ => FlushExpired(), null, FlushInterval, FlushInterval);
   302→        }
   303→
   304→        public bool CanHandle(EventEnvelope envelope)
   305→            => envelope.EventType is CommitEventType or ProdDeployEventType;
   306→
   307→        public async ValueTask<IEnumerable<KpiCalculationResult>> ProcessAsync(
   308→            EventEnvelope envelope,
   309→            CancellationToken ct = default)
   310→        {
   311→            switch (envelope.EventType)
   312→            {
   313→                case CommitEventType:
   314→                    {
   315→                        var commitSha  = envelope.Metadata["CommitSha"]!;
   316→                        _commitTimestamps[commitSha] = envelope.Created.UtcDateTime;
   317→                        break;
   318→                    }
   319→
   320→                case ProdDeployEventType:
   321→                    {
   322→                        var commitSha = envelope.Metadata["CommitSha"]!;
   323→                        if (_commitTimestamps.TryRemove(commitSha, out var commitTime))
   324→                        {
   325→                            var leadTimeMinutes = (envelope.Created.UtcDateTime - commitTime).TotalMinutes;
   326→                            var repo            = envelope.Metadata["Repository"]!;
   327→
   328→                            var kpiRow = new KpiCalculationResult
   329→                            {
   330→                                KpiName        = KpiName,
   331→                                WindowStartUtc = commitTime,
   332→                                WindowEndUtc   = envelope.Created.UtcDateTime,
   333→                                Value          = (decimal)leadTimeMinutes,
   334→                                Dimensions = new Dictionary<string, string>
   335→                                {
   336→                                    ["repository"] = repo
   337→                                }
   338→                            };
   339→                            return new[] { kpiRow };
   340→                        }
   341→                        break;
   342→                    }
   343→            }
   344→
   345→            return Array.Empty<KpiCalculationResult>();
   346→        }
   347→
   348→        private void FlushExpired()
   349→        {
   350→            var threshold = DateTime.UtcNow.AddHours(-24); // assume deploy happens within 24 h
   351→            foreach (var kvp in _commitTimestamps)
   352→            {
   353→                if (kvp.Value < threshold && _commitTimestamps.TryRemove(kvp.Key, out _))
   354→                {
   355→                    _logger.LogDebug(
   356→                        "Dropped stale commit {CommitSha} for deployment lead-time KPI (older than 24h).",
   357→                        kvp.Key);
   358→                }
   359→            }
   360→        }
   361→
   362→        public void Dispose()
   363→        {
   364→            _flushTimer.Dispose();
   365→        }
   366→    }
