   383→    /// <summary>
   384→    /// Production-ready S3 writer implementation with retry/back-off and partitioned key structure.
   385→    /// </summary>
   386→    internal sealed class S3KpiWriter : IS3KpiWriter
   387→    {
   388→        private readonly IAmazonS3                 _s3;
   389→        private readonly string                    _bucket;
   390→        private readonly ILogger<S3KpiWriter>      _logger;
   391→
   392→        private static readonly AmazonS3RetryPolicy RetryPolicy = new();
   393→
   394→        public S3KpiWriter(IAmazonS3 s3, string bucket, ILogger<S3KpiWriter> logger)
   395→        {
   396→            _s3     = s3     ?? throw new ArgumentNullException(nameof(s3));
   397→            _bucket = bucket ?? throw new ArgumentNullException(nameof(bucket));
   398→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   399→        }
   400→
   401→        public async ValueTask WriteAsync(
   402→            IEnumerable<KpiCalculationResult> rows,
   403→            CancellationToken                 ct = default)
   404→        {
   405→            ArgumentNullException.ThrowIfNull(rows);
   406→
   407→            var nowUtc     = DateTime.UtcNow;
   408→            var partition  = $"{nowUtc:yyyy/MM/dd}";
   409→            var objectKey  = $"kpi/partition_date={partition}/{Guid.NewGuid():N}.jsonl";
   410→
   411→            // Serialise as ND-JSON
   412→            var jsonLines  = string.Join('\n', rows.Select(row => System.Text.Json.JsonSerializer.Serialize(row)));
   413→
   414→            var request = new PutObjectRequest
   415→            {
   416→                BucketName  = _bucket,
   417→                Key         = objectKey,
   418→                ContentBody = jsonLines,
   419→                ContentType = "application/json"
   420→            };
   421→
   422→            await RetryPolicy.ExecuteAsync(
   423→                async () => await _s3.PutObjectAsync(request, ct).ConfigureAwait(false),
   424→                ct).ConfigureAwait(false);
   425→
   426→            _logger.LogDebug("Wrote {RowCount} KPI rows to s3://{Bucket}/{Key}.", rows.Count(), _bucket, objectKey);
   427→        }
   428→
   429→        public ValueTask DisposeAsync() => ValueTask.CompletedTask;
   430→    }
   431→
   432→    /// <summary>
   433→    /// Declarative, exponential back-off retry wrapper for S3 operations.
   434→    /// </summary>
   435→    internal sealed class AmazonS3RetryPolicy
   436→    {
   437→        private static readonly TimeSpan[] BackOffSchedule =
   438→        {
   439→            TimeSpan.FromMilliseconds(100),
   440→            TimeSpan.FromMilliseconds(250),
   441→            TimeSpan.FromMilliseconds(500),
   442→            TimeSpan.FromSeconds(1),
   443→            TimeSpan.FromSeconds(2)
   444→        };
   445→
   446→        public async Task ExecuteAsync(Func<Task> operation, CancellationToken ct)
   447→        {
   448→            var attempt = 0;
   449→            Exception? lastError = null;
   450→
   451→            foreach (var delay in BackOffSchedule.Append(TimeSpan.Zero))
   452→            {
   453→                try
   454→                {
   455→                    ct.ThrowIfCancellationRequested();
   456→                    await operation().ConfigureAwait(false);
   457→                    return; // success
   458→                }
   459→                catch (Exception ex) when (IsTransient(ex))
   460→                {
   461→                    lastError = ex;
   462→                    attempt++;
   463→                    if (delay > TimeSpan.Zero)
   464→                        await Task.Delay(delay, ct).ConfigureAwait(false);
   465→                }
   466→            }
   467→
   468→            throw new InvalidOperationException(
   469→                $"S3 operation failed after {attempt} retries.", lastError);
   470→        }
   471→
   472→        private static bool IsTransient(Exception ex)
   473→        {
   474→            // TODO: Add richer fault-analysis; for now assume all AmazonS3Exception with 5xx are transient.
   475→            return ex is AmazonS3Exception s3Ex && (int)s3Ex.StatusCode >= 500;
   476→        }
   477→    }
