    25→    /// <summary>
    26→    /// Common contract for all KPI computation strategies.
    27→    /// Implementations MUST be stateless and thread-safe.
    28→    /// </summary>
    29→    public interface IKpiComputationStrategy
    30→    {
    31→        /// <summary>
    32→        /// Friendly identifier used for routing and diagnostics.
    33→        /// </summary>
    34→        string StrategyId { get; }
    35→
    36→        /// <summary>
    37→        /// Computes a KPI for the specified time-range and entity scope.
