    73→    #region 📦 Registry & Engine
    74→
    75→    /// <summary>
    76→    /// Thread-safe registry responsible for resolving KPI computation strategies at runtime.
    77→    /// Typically wired into the DI container with a Singleton lifetime.
    78→    /// </summary>
    79→    public sealed class KpiComputationStrategyRegistry
    80→    {
    81→        private readonly ConcurrentDictionary<string, IKpiComputationStrategy> _strategies = new();
    82→
    83→        public KpiComputationStrategyRegistry(IEnumerable<IKpiComputationStrategy> discoveredStrategies,
    84→                                              ILogger<KpiComputationStrategyRegistry> logger)
    85→        {
    86→            foreach (var strategy in discoveredStrategies)
    87→            {
    88→                if (!_strategies.TryAdd(strategy.StrategyId, strategy))
    89→                {
    90→                    logger.LogWarning("Duplicate KPI strategy registration detected for {StrategyId}", strategy.StrategyId);
    91→                }
    92→                else
    93→                {
    94→                    logger.LogInformation("Registered KPI strategy: {StrategyId}", strategy.StrategyId);
    95→                }
    96→            }
    97→        }
    98→
    99→        /// <summary>
   100→        /// Resolve a strategy by its logical identifier.
   101→        /// </summary>
   102→        /// <exception cref="KeyNotFoundException">Thrown when the strategy cannot be resolved.</exception>
   103→        public IKpiComputationStrategy Resolve(string strategyId)
   104→        {
   105→            if (_strategies.TryGetValue(strategyId, out var strategy))
   106→                return strategy;
   107→
   108→            throw new KeyNotFoundException(
   109→                $"No KPI computation strategy has been registered with id '{strategyId}'.");
   110→        }
   111→
   112→        /// <summary>
   113→        /// Returns all known strategy identifiers.
   114→        /// </summary>
   115→        public IReadOnlyCollection<string> KnownStrategies => _strategies.Keys.ToArray();
   116→    }
