   118→    /// <summary>
   119→    /// Orchestrates KPI computation by delegating to a concrete strategy.
   120→    /// Serves as an anti-corruption layer between the Lambda handler and strategy implementations.
   121→    /// </summary>
   122→    public sealed class KpiComputationEngine
   123→    {
   124→        private readonly KpiComputationStrategyRegistry _registry;
   125→        private readonly ILogger<KpiComputationEngine> _logger;
   126→
   127→        public KpiComputationEngine(KpiComputationStrategyRegistry registry,
   128→                                    ILogger<KpiComputationEngine> logger)
   129→        {
   130→            _registry = registry;
   131→            _logger = logger;
   132→        }
   133→
   134→        /// <summary>
   135→        /// Compute a KPI using the strategy specified in the context parameters ("strategyId").
   136→        /// Unknown strategies are automatically routed to a default pass-through result to avoid
   137→        /// poisoning the entire batch.
   138→        /// </summary>
   139→        public async Task<KpiComputationResult?> ComputeAsync(
   140→            KpiComputationContext context,
   141→            CancellationToken cancellationToken = default)
   142→        {
   143→            if (!context.Parameters.TryGetValue("strategyId", out var strategyIdElement) ||
   144→                strategyIdElement.ValueKind != JsonValueKind.String)
   145→            {
   146→                _logger.LogError("KPI context is missing 'strategyId' parameter");
   147→                return null;
   148→            }
   149→
   150→            var strategyId = strategyIdElement.GetString()!;
   151→            IKpiComputationStrategy strategy;
   152→
   153→            try
   154→            {
   155→                strategy = _registry.Resolve(strategyId);
   156→            }
   157→            catch (KeyNotFoundException ex)
   158→            {
   159→                _logger.LogError(ex, "Failed to resolve KPI strategy '{StrategyId}'", strategyId);
   160→                return null;
   161→            }
   162→
   163→            using var activity = Telemetry.StartActivity("ComputeKpi", ("strategyId", strategyId));
   164→
   165→            _logger.LogInformation("Starting KPI computation: {StrategyId} for Tenant={TenantId}", strategyId, context.TenantId);
   166→
   167→            try
   168→            {
   169→                var result = await strategy.ComputeAsync(context, _logger, cancellationToken).ConfigureAwait(false);
   170→
   171→                _logger.LogInformation("Computed KPI '{KpiKey}' for Tenant={TenantId}", result.KpiKey, result.TenantId);
   172→                return result;
   173→            }
   174→            catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
   175→            {
   176→                _logger.LogWarning("KPI computation was cancelled (Strategy={StrategyId}, Tenant={TenantId})",
   177→                    strategyId, context.TenantId);
   178→                return null;
   179→            }
   180→            catch (Exception ex)
   181→            {
   182→                _logger.LogError(ex,
   183→                    "Unhandled error while computing KPI (Strategy={StrategyId}, Tenant={TenantId})",
   184→                    strategyId, context.TenantId);
   185→                throw; // Bubble up to Lambda error handler → DLQ
   186→            }
   187→        }
   188→    }
