   192→    #region 📊 Exemplary Strategies
   193→
   194→    /// <summary>
   195→    /// Calculates the Focus Time Ratio:
   196→    /// (Total Focus Hours) / (Total Working Hours)
   197→    /// Focus hours are defined as continuous blocks of time ≥ 2h with
   198→    /// no meetings, no commit activity, and no Slack messages.
   199→    /// </summary>
   200→    public sealed class FocusTimeRatioStrategy : IKpiComputationStrategy
   201→    {
   202→        public string StrategyId => "focus-time-ratio";
   203→
   204→        public async Task<KpiComputationResult> ComputeAsync(
   205→            KpiComputationContext context,
   206→            ILogger logger,
   207→            CancellationToken cancellationToken = default)
   208→        {
   209→            // Simulate async I/O, e.g. reading additional artefacts from S3
   210→            await Task.Yield();
   211→
   212→            var focusIntervals = new List<DateTimeOffset>();
   213→            var workingIntervals = new List<DateTimeOffset>();
   214→
   215→            foreach (var e in context.RawEvents.Iterate())
   216→            {
   217→                cancellationToken.ThrowIfCancellationRequested();
   218→
   219→                switch (e)
   220→                {
   221→                    case TimeEntryEvent tee:
   222→                        workingIntervals.Add(tee.Timestamp);
   223→                        break;
   224→                    case MeetingEvent me:
   225→                        // Mark as non-focus
   226→                        break;
   227→                    case CommitEvent ce:
   228→                        // Non-focus
   229→                        break;
   230→                    default:
   231→                        break;
   232→                }
   233→
   234→                // For demo purposes we synthesise results
   235→                if (e.Timestamp.Minute % 13 == 0)
   236→                    focusIntervals.Add(e.Timestamp);
   237→            }
   238→
   239→            var totalWorkingHours = workingIntervals.Count / 4.0; // Fake math
   240→            var totalFocusHours   = focusIntervals.Count   / 4.0;
   241→
   242→            var ratio = totalWorkingHours == 0 ? 0 : totalFocusHours / totalWorkingHours;
   243→
   244→            var payloadJson = JsonSerializer.SerializeToElement(new
   245→            {
   246→                ratio,
   247→                totalFocusHours,
   248→                totalWorkingHours
   249→            });
   250→
   251→            return new KpiComputationResult(
   252→                context.TenantId,
