    60→        public async Task HandleAsync(KinesisEvent kinesisEvent, ILambdaContext context)
    61→        {
    62→            _logger.LogInformation("Received {RecordCount} records in batch {RequestId}", 
    63→                kinesisEvent.Records.Count, context.AwsRequestId);
    64→
    65→            var uploadTasks = new List<Task>();
    66→
    67→            foreach (var record in kinesisEvent.Records)
    68→            {
    69→                uploadTasks.Add(ProcessRecordAsync(record, context));
    70→            }
    71→
    72→            await Task.WhenAll(uploadTasks).ConfigureAwait(false);
