    76→        private async Task ProcessRecordAsync(KinesisEvent.KinesisEventRecord record, ILambdaContext context)
    77→        {
    78→            CancellationToken token = context.CancellationToken;
    79→
    80→            if (token.IsCancellationRequested)
    81→            {
    82→                _logger.LogWarning("Cancellation requested before processing record");
    83→                return;
    84→            }
    85→
    86→            RawEvent raw;
    87→            try
    88→            {
    89→                var payloadJson = Encoding.UTF8.GetString(record.Kinesis.Data.Span);
    90→                raw = JsonSerializer.Deserialize<RawEvent>(payloadJson, JsonOptions.Options)
    91→                      ?? throw new InvalidDataException("Unable to deserialize event.");
    92→            }
    93→            catch (Exception ex)
    94→            {
    95→                _logger.LogError(ex, "Failed to deserialize record; pushing to DLQ");
    96→                await PushToDlqAsync(record).ConfigureAwait(false);
    97→                return;
    98→            }
    99→
   100→            try
   101→            {
   102→                var transformed = await _dispatcher.TransformAsync(raw, token).ConfigureAwait(false);
   103→                await PersistAsync(transformed, token).ConfigureAwait(false);
   104→            }
