   106→            {
   107→                _logger.LogWarning(ex, "No transformation found for EventType={EventType}", raw.EventType);
   108→                await PushToDlqAsync(record).ConfigureAwait(false);
   109→            }
   110→            catch (Exception ex)
   111→            {
   112→                _logger.LogError(ex, "Unhandled error while processing record");
   113→                await PushToDlqAsync(record).ConfigureAwait(false);
   114→            }
   115→        }
