   143→            var outputStream = Environment.GetEnvironmentVariable(OutputStreamEnvVar);
   144→            if (!string.IsNullOrEmpty(outputStream))
   145→            {
   146→                await _kinesisClient.PutRecordAsync(new PutRecordRequest
   147→                {
   148→                    StreamName   = outputStream,
   149→                    Data         = memStream,
   150→                    PartitionKey = evt.TenantId
   151→                }, token).ConfigureAwait(false);
