   234→    internal sealed class TransformationDispatcher : ITransformationDispatcher
   235→    {
   236→        private readonly IDictionary<string, ITransformationStrategy> _strategyMap;
   237→        private readonly ILogger<TransformationDispatcher> _logger;
   238→
   239→        public TransformationDispatcher(IEnumerable<ITransformationStrategy> strategies,
   240→                                        ILogger<TransformationDispatcher> logger)
   241→        {
   242→            _logger = logger;
   243→            _strategyMap = new ConcurrentDictionary<string, ITransformationStrategy>(StringComparer.OrdinalIgnoreCase);
   244→
   245→            foreach (var strategy in strategies)
   246→            {
   247→                if (_strategyMap.ContainsKey(strategy.EventType))
   248→                {
   249→                    _logger.LogWarning("Duplicate strategy registration for EventType={EventType}", strategy.EventType);
   250→                    continue;
   251→                }
   252→
   253→                _strategyMap[strategy.EventType] = strategy;
   254→            }
   255→        }
