   281→    internal sealed class FocusTimeStrategy : ITransformationStrategy
   282→    {
   283→        private const string MetricName = "focus_time_minutes";
   284→
   285→        public string EventType => "IDE_SESSION";
   286→
   287→        public Task<TransformedEvent> TransformAsync(RawEvent raw, CancellationToken token)
   288→        {
   289→            // Example transformation: extract "activeMinutes" from payload.
   290→            if (!raw.Payload.TryGetProperty("activeMinutes", out var activeMinutesElement) ||
   291→                !activeMinutesElement.TryGetInt32(out var activeMinutes))
   292→            {
   293→                throw new InvalidDataException("Missing activeMinutes in payload");
   294→            }
   295→
   296→            var transformed = new TransformedEvent
   297→            {
   298→                TenantId   = raw.TenantId,
   299→                EventType  = "FOCUS_TIME",
   300→                OccurredAt = raw.OccurredAt,
   301→                Metrics    = new Dictionary<string, object?>
   302→                {
   303→                    [MetricName] = activeMinutes
   304→                }
   305→            };
   306→
   307→            return Task.FromResult(transformed);
