   341→    /// <summary>
   342→    ///     Calculates estimated meeting cost from calendar events.
   343→    /// </summary>
   344→    internal sealed class MeetingCostStrategy : ITransformationStrategy
   345→    {
   346→        private const string MetricName = "meeting_cost_usd";
   347→        private const decimal HourlyCostDefault = 75m;
   348→
   349→        public string EventType => "CALENDAR_MEETING";
   350→
   351→        public Task<TransformedEvent> TransformAsync(RawEvent raw, CancellationToken token)
   352→        {
   353→            int attendeeCount = raw.Payload.GetProperty("attendeeCount").GetInt32();
   354→            decimal hourlyRate = raw.Payload.TryGetProperty("hourlyRateUsd", out var rateElement) &&
   355→                                 rateElement.TryGetDecimal(out var rate)
   356→                                 ? rate
   357→                                 : HourlyCostDefault;
   358→
   359→            var durationMinutes = raw.Payload.GetProperty("durationMinutes").GetInt32();
   360→            var cost = attendeeCount * hourlyRate * (durationMinutes / 60m);
   361→
   362→            var transformed = new TransformedEvent
   363→            {
   364→                TenantId   = raw.TenantId,
   365→                EventType  = "MEETING_COST",
   366→                OccurredAt = raw.OccurredAt,
   367→                Metrics    = new Dictionary<string, object?>
   368→                {
   369→                    [MetricName] = Math.Round(cost, 2)
   370→                }
   371→            };
   372→
   373→            return Task.FromResult(transformed);
   374→        }
