    75→    /// <summary>
    76→    /// Calculates focus-time ratio KPI from calendar/IDE activity signals.
    77→    /// </summary>
    78→    public sealed class FocusTimeRatioStrategy : ITransformationStrategy
    79→    {
    80→        public Task<TransformedRecord> TransformAsync(RawRecord rawRecord, CancellationToken token = default)
    81→        {
    82→            dynamic payload = JsonConvert.DeserializeObject(rawRecord.PayloadJson)!;
    83→            double deepWorkMinutes = payload.deepWorkMinutes;
    84→            double totalMinutes    = payload.totalMinutes;
    85→
    86→            double ratio = totalMinutes == 0 ? 0 : deepWorkMinutes / totalMinutes;
    87→
    88→            return Task.FromResult(new TransformedRecord
    89→            {
    90→                PartitionKey      = $"{payload.userId}_{rawRecord.Timestamp:yyyyMMdd}",
    91→                EventDate         = rawRecord.Timestamp,
    92→                MetricType        = MetricType.FocusTimeRatio,
    93→                CalculatedFields  = new Dictionary<string, object>
    94→                {
    95→                    ["FocusTimeRatio"] = ratio,
    96→                    ["DeepWorkMinutes"]= deepWorkMinutes,
    97→                    ["TotalMinutes"]   = totalMinutes
    98→                }
    99→            });
   100→        }
