     2→// File: src/module_36.cs
     3→// Project: PulseOps Warehouse — Serverless Productivity Intelligence Fabric
     4→//
     5→// Description:
     6→//     Transformation strategy infrastructure + concrete Focus-Time ratio implementation.
     7→//     Demonstrates Strategy-Pattern, parallel processing, structured logging, and
     8→//     resiliency best-practices.  This file is shared by multiple Lambda functions
     9→//     that need a plug-and-play metric computation engine.
    10→//
    11→// ReSharper disable PossibleMultipleEnumeration
    12→
    13→using System;
    14→using System.Collections.Concurrent;
    15→using System.Collections.Generic;
    16→using System.Diagnostics;
    17→using System.Linq;
    18→using System.Text.Json;
    19→using System.Threading;
    20→using System.Threading.Tasks;
    21→using Microsoft.Extensions.Logging;
    22→
    23→namespace PulseOps.Warehouse.Transformations
    24→{
    25→    #region Contracts
    26→
    27→    /// <summary>
    28→    ///     Generic contract for a transformation strategy.
    29→    /// </summary>
    30→    /// <typeparam name="TIn">Up-stream raw event payload.</typeparam>
    31→    /// <typeparam name="TOut">Down-stream analytical entity.</typeparam>
    32→    public interface ITransformationStrategy<in TIn, TOut>
    33→    {
    34→        /// <summary>Unique, human-readable identifier.</summary>
    35→        string Name { get; }
    36→
    37→        /// <summary>Transforms a set of <typeparamref name="TIn" /> into <typeparamref name="TOut" />.</summary>
    38→        /// <param name="input">Events partition belonging to the same routing key.</param>
    39→        /// <param name="cancellationToken">Co-operative cancellation token.</param>
    40→        Task<TOut> TransformAsync(IEnumerable<TIn> input, CancellationToken cancellationToken = default);
    41→    }
    42→
    43→    #endregion
    44→
    45→    #region Registry
    46→
    47→    /// <summary>
    48→    ///     Thread-safe registry that supports dynamic discovery and hot-swapping of
    49→    ///     transformation strategies at runtime.  The registry name is case-insensitive
    50→    ///     to avoid subtle deployment mistakes when multiple teams contribute.
    51→    /// </summary>
    52→    public static class TransformationStrategyRegistry
    53→    {
    54→        private static readonly ConcurrentDictionary<string, object> _registry =
    55→            new(StringComparer.OrdinalIgnoreCase);
    56→
    57→        /// <summary>Registers or overrides a strategy instance.</summary>
    58→        public static void Register<TIn, TOut>(ITransformationStrategy<TIn, TOut> strategy)
    59→        {
    60→            if (strategy == null) throw new ArgumentNullException(nameof(strategy));
    61→            _registry[strategy.Name] = strategy;
    62→        }
    63→
    64→        /// <summary>Fetches a strategy by name, throwing if not found.</summary>
    65→        public static ITransformationStrategy<TIn, TOut> Resolve<TIn, TOut>(string name)
    66→        {
    67→            if (!_registry.TryGetValue(name, out var boxed))
    68→                throw new KeyNotFoundException($"Transformation '{name}' not registered.");
    69→
    70→            if (boxed is ITransformationStrategy<TIn, TOut> typed) return typed;
    71→
    72→            throw new InvalidCastException(
    73→                $"Strategy '{name}' is registered for a different payload shape.");
    74→        }
    75→
    76→        /// <summary>Returns all registered strategy identifiers.</summary>
    77→        public static IReadOnlyCollection<string> List()
    78→            => _registry.Keys.ToArray();
    79→    }
    80→
    81→    #endregion
    82→
    83→    #region Domain Models
    84→
    85→    /// <summary>
    86→    ///     Minimal calendar event projection required for focus-time computation.
    87→    /// </summary>
    88→    public sealed record CalendarEvent(
    89→        string UserPrincipalName,
    90→        DateTimeOffset Start,
    91→        DateTimeOffset End,
    92→        string? Classification // e.g. "Focus", "Meeting", "Personal", etc.
    93→    )
    94→    {
    95→        public TimeSpan Duration => End - Start;
    96→    }
    97→
    98→    /// <summary>Analytical metric entity materialized by <see cref="FocusTimeRatioStrategy" />.</summary>
    99→    public sealed record FocusTimeRatioKpi(
   100→        string UserPrincipalName,
   101→        DateOnly Day,
   102→        double FocusMinutes,
   103→        double TotalMinutes,
   104→        double FocusRatio
   105→    );
   106→
   107→    #endregion
   108→
   109→    #region Strategy Implementation
   110→
   111→    /// <summary>
   112→    ///     Calculates focus-time ratio per user per day:
   113→    ///         FocusRatio = FocusMinutes / TotalMinutes
   114→    ///     where FocusMinutes are calendar events classified as "Focus" or "Deep-Work".
   115→    /// </summary>
   116→    public sealed class FocusTimeRatioStrategy : ITransformationStrategy<CalendarEvent, IReadOnlyCollection<FocusTimeRatioKpi>>
   117→    {
   118→        public const string StrategyId = "focus-time-ratio@v1";
   119→        private const string DefaultFocusLabel = "Focus";
   120→        private static readonly string[] EquivalentFocusLabels = { "Deep-Work", "Heads-Down" };
   121→
   122→        public string Name => StrategyId;
