   388→        public async Task DeadLetterAsync(KinesisEvent.KinesisEventRecord rawRecord, Exception ex, CancellationToken ct)
   389→        {
   390→            // Pipe to DLQ – in demo we just log.  In production it’s an SQS DLQ.
   391→            _log.Warning(ex, "Dead-lettering record {@PartitionKey}", rawRecord.Kinesis.PartitionKey);
   392→            await Task.CompletedTask;
   393→        }
   394→
   395→        private async Task FlushAsync(CancellationToken ct)
   396→        {
   397→            if (_buffer.IsEmpty) return;
   398→
   399→            var batch = new List<Amazon.Kinesis.Model.PutRecordsRequestEntry>();
   400→            while (batch.Count < 500 && _buffer.TryDequeue(out var entry))
   401→            {
   402→                batch.Add(entry);
   403→            }
   404→
   405→            if (batch.Count == 0) return;
   406→
   407→            var request = new Amazon.Kinesis.Model.PutRecordsRequest
   408→            {
   409→                StreamName = _targetStreamName,
   410→                Records    = batch
   411→            };
   412→
   413→            var response = await _kinesis.PutRecordsAsync(request, ct);
   414→
   415→            if (response.FailedRecordCount > 0)
   416→            {
   417→                _log.Error("Failed to write {Failed}/{Total} records to stream {Stream}",
   418→                           response.FailedRecordCount, batch.Count, _targetStreamName);
   419→            }
   420→            else
   421→            {
   422→                _log.Information("Flushed {Count} transformed events to stream {Stream}",
   423→                                 batch.Count, _targetStreamName);
   424→            }
   425→        }
   426→
   427→        public void Dispose() => _ = FlushAsync(CancellationToken.None);
   428→    }
   429→}
